  1	import * as React from 'react';
  2	import { CapacityAutoScaling } from '@odf/core/components/create-storage-system/create-storage-system-steps/capacity-and-nodes-step/capacity-autoscaling';
  3	import { createStorageAutoScaler } from '@odf/core/components/create-storage-system/payloads';
  4	import { VALIDATIONS } from '@odf/core/components/utils/common-odf-install-el';
  5	import { NO_PROVISIONER } from '@odf/core/constants';
  6	import { scResource } from '@odf/core/resources';
  7	import { ValidationType } from '@odf/core/types';
  8	import {
  9	  getOsdAmount,
 10	  isValidCapacityAutoScalingConfig,
 11	} from '@odf/core/utils/ocs';
 12	import {
 13	  CapacityAutoscalingStatus,
 14	  ColoredIconProps,
 15	  DEFAULT_DEVICECLASS,
 16	  getName,
 17	  getNamespace,
 18	  GrayUnknownIcon,
 19	  GreenCheckCircleIcon,
 20	  RedExclamationCircleIcon,
 21	  RedExclamationTriangleIcon,
 22	  StatusBox,
 23	  StorageAutoScalerKind,
 24	  StorageClassResourceKind,
 25	} from '@odf/shared';
 26	import { dateTimeFormatter } from '@odf/shared/details-page/datetime';
 27	import { LoadingInline } from '@odf/shared/generic/Loading';
 28	import { StorageClusterActionModalProps } from '@odf/shared/modals/common';
 29	import { ModalBody, ModalFooter, ModalHeader } from '@odf/shared/modals/Modal';
 30	import {
 31	  StorageAutoScalerModel,
 32	  StorageClusterModel,
 33	} from '@odf/shared/models';
 34	import { DeviceSet, StorageClusterKind } from '@odf/shared/types';
 35	import { useCustomTranslation } from '@odf/shared/useCustomTranslationHook';
 36	import { getStorageAutoScalerName, referenceForModel } from '@odf/shared/utils';
 37	import {
 38	  k8sDelete,
 39	  k8sPatch,
 40	  Patch,
 41	  useK8sWatchResource,
 42	} from '@openshift-console/dynamic-plugin-sdk';
 43	import { SVGIconProps } from '@patternfly/react-icons/dist/esm/createIcon';
 44	import * as _ from 'lodash-es';
 45	import {
 46	  Alert,
 47	  AlertVariant,
 48	  Button,
 49	  ButtonVariant,
 50	  Modal,
 51	  ModalVariant,
 52	} from '@patternfly/react-core';
 53	import { InProgressIcon, RunningIcon } from '@patternfly/react-icons';
 54	import './capacity-autoscaling-modal.scss';
 55	
 56	const getFormattedTime = (timestamp: string) =>
 57	  dateTimeFormatter.format(new Date(timestamp));
 58	
 59	type CapacityAutoscalingStatusProps = {
 60	  currentStatus: string;
 61	  error: StorageAutoScalerKind['status']['error'];
 62	  lastExpansion?: StorageAutoScalerKind['status']['lastExpansion'];
 63	};
 64	
 65	const CapacityAutoscalingCurrentStatus: React.FC<
 66	  CapacityAutoscalingStatusProps
 67	> = ({ currentStatus, error, lastExpansion }) => {
 68	  const { t } = useCustomTranslation();
 69	
 70	  let StatusIcon:
 71	    | React.ComponentClass<SVGIconProps>
 72	    | React.FC<ColoredIconProps>;
 73	  let statusText: string;
 74	  switch (currentStatus) {
 75	    case CapacityAutoscalingStatus.NotStarted:
 76	      StatusIcon = RunningIcon;
 77	      statusText = t('Actively monitoring, waiting for trigger');
 78	      break;
 79	    case CapacityAutoscalingStatus.InProgress:
 80	      StatusIcon = InProgressIcon;
 81	      statusText = t('Scaling is in progress');
 82	      if (lastExpansion?.startTime) {
 83	        statusText += `, ${t('started at ')} ${getFormattedTime(lastExpansion.startTime)}`;
 84	      }
 85	      break;
 86	    case CapacityAutoscalingStatus.Succeeded:
 87	      StatusIcon = GreenCheckCircleIcon;
 88	      statusText = t('Completed');
 89	      if (lastExpansion?.completionTime) {
 90	        statusText += `, ${getFormattedTime(lastExpansion.completionTime)}`;
 91	      }
 92	      break;
 93	    case CapacityAutoscalingStatus.Failed:
 94	      StatusIcon = RedExclamationCircleIcon;
 95	      statusText = t('Failed');
 96	      if (error?.timestamp) {
 97	        statusText += `, ${getFormattedTime(error.timestamp)}`;
 98	      }
 99	      if (error?.message) {
100	        statusText += `: ${error.message}`;
101	      }
102	      break;
103	    case CapacityAutoscalingStatus.Invalid:
104	      StatusIcon = RedExclamationTriangleIcon;
105	      statusText = t('Invalid');
106	      if (error?.timestamp) {
107	        statusText += `, ${getFormattedTime(error.timestamp)}`;
108	      }
109	      if (error?.message) {
110	        statusText += `: ${error.message}`;
111	      }
112	      break;
113	    default:
114	      StatusIcon = GrayUnknownIcon;
115	      statusText = t('Unknown');
116	  }
117	
118	  return (
119	    <div className="pf-v6-u-mt-sm pf-v6-u-font-size-sm">
120	      <span className="pf-v6-u-font-family-heading pf-v6-u-mr-sm">
121	        {t('Current status:')}
122	      </span>
123	      <StatusIcon className="pf-v6-u-mr-sm" />
124	      {statusText}
125	    </div>
126	  );
127	};
128	
129	const CapacityAutoscalingModal: React.FC<StorageClusterActionModalProps> = ({
130	  extraProps: { storageCluster: actionStorageCluster },
131	  closeModal,
132	  isOpen,
133	}) => {
134	  const { t } = useCustomTranslation();
135	  const [enable, setEnable] = React.useState(false);
136	  const [capacityLimit, setCapacityLimit] = React.useState<string>(null);
137	  const [validation, setValidation] = React.useState('');
138	  const [inProgress, setInProgress] = React.useState(false);
139	  const [errorMessage, setError] = React.useState<Error>(null);
140	  const [storageCluster] = useK8sWatchResource<StorageClusterKind>({
141	    kind: referenceForModel(StorageClusterModel),
142	    name: getName(actionStorageCluster),
143	    namespace: getNamespace(actionStorageCluster),
144	  });
145	  const [
146	    storageAutoScalers,
147	    storageAutoScalerLoaded,
148	    storageAutoScalerLoadError,
149	  ] = useK8sWatchResource<StorageAutoScalerKind[]>({
150	    kind: referenceForModel(StorageAutoScalerModel),
151	    isList: true,
152	    namespace: getNamespace(storageCluster),
153	  });
154	
155	  // Get no-provisioner storage classes.
156	  const [storageClasses, scLoaded, scLoadError] =
157	    useK8sWatchResource<StorageClassResourceKind[]>(scResource);
158	  const noProvisionerSCNames = storageClasses
159	    ?.filter((sc) => sc.provisioner === NO_PROVISIONER)
160	    .map((sc) => getName(sc));
161	
162	  const isLoaded = storageAutoScalerLoaded && scLoaded;
163	  const isLoadError = storageAutoScalerLoadError || scLoadError;
164	
165	  const deviceSets = storageCluster?.spec?.storageDeviceSets?.filter(
166	    (deviceSet: DeviceSet) =>
167	      _.isEmpty(deviceSet.deviceClass) ||
168	      deviceSet.deviceClass.toLowerCase() === DEFAULT_DEVICECLASS
169	  );
170	  // Autoscaling is not allowed if any storageDeviceSet is managed by
171	  // any no-provisioner storage class.
172	  const isCapacityAutoScalingAllowedInDay2 = _.isEmpty(
173	    deviceSets?.find((deviceSet: DeviceSet) =>
174	      noProvisionerSCNames.includes(
175	        deviceSet.dataPVCTemplate.spec.storageClassName
176	      )
177	    )
178	  );
179	
180	  const clusterStorageAutoScalers = storageAutoScalers?.filter(
181	    (autoScaler) =>
182	      autoScaler.spec.storageCluster.name === getName(storageCluster) &&
183	      (_.isEmpty(autoScaler.spec.deviceClass) ||
184	        autoScaler.spec.deviceClass.toLowerCase() === DEFAULT_DEVICECLASS)
185	  );
186	  // Pick the ui-created autoscaler if it exists.
187	  let storageAutoScaler = clusterStorageAutoScalers?.find(
188	    (autoScaler) =>
189	      getName(autoScaler) === getStorageAutoScalerName(storageCluster)
190	  );
191	  if (!storageAutoScaler && clusterStorageAutoScalers.length > 0) {
192	    storageAutoScaler = clusterStorageAutoScalers[0];
193	  }
194	
195	  const alreadyEnabled = !_.isEmpty(storageAutoScaler);
196	  let canEdit = isCapacityAutoScalingAllowedInDay2 && isLoaded && !isLoadError;
197	  const phase = storageAutoScaler?.status?.phase;
198	  const lastExpansion = storageAutoScaler?.status?.lastExpansion;
199	  const autoScalerError = storageAutoScaler?.status?.error;
200	
201	  // Getting the osd size from the 1st device set is enough as we don't support
202	  // heterogeneous OSD sizes. See: https://access.redhat.com/articles/5001441
203	  const osdSize =
204	    storageCluster?.spec?.storageDeviceSets[0].dataPVCTemplate.spec.resources
205	      .requests.storage;
206	  const osdAmount = deviceSets
207	    ?.map((deviceSet: DeviceSet) =>
208	      getOsdAmount(deviceSet.count, deviceSet.replica)
209	    )
210	    .reduce((accumulator: number, current: number) => accumulator + current);
211	
212	  const validate = React.useCallback(
213	    (isEnabled: boolean, newCapacityLimit: string) =>
214	      setValidation(
215	        isValidCapacityAutoScalingConfig(isEnabled, newCapacityLimit)
216	          ? ''
217	          : String(VALIDATIONS(ValidationType.CAPACITY_AUTOSCALING, t).title)
218	      ),
219	    [t]
220	  );
221	
222	  const onChange = (_ev, checked: boolean) => {
223	    setEnable(checked);
224	    validate(checked, capacityLimit);
225	  };
226	  const onSelect = (selected: string) => {
227	    setCapacityLimit(selected);
228	    validate(enable, selected);
229	  };
230	
231	  const save = async (): Promise<void> => {
232	    setError(null);
233	    setInProgress(true);
234	
235	    try {
236	      if (enable) {
237	        if (!alreadyEnabled) {
238	          await createStorageAutoScaler(capacityLimit, storageCluster);
239	        } else {
240	          const patch: Patch = {
241	            op: 'replace',
242	            path: '/spec/storageCapacityLimit',
243	            value: capacityLimit,
244	          };
245	          await k8sPatch({
246	            model: StorageAutoScalerModel,
247	            resource: storageAutoScaler,
248	            data: [patch],
249	          });
250	        }
251	      } else if (!enable && alreadyEnabled) {
252	        if (phase === CapacityAutoscalingStatus.InProgress) {
253	          throw new Error(
254	            t(
255	              'Automatic capacity scaling cannot be disabled while scaling is in progress'
256	            )
257	          );
258	        }
259	
260	        await k8sDelete({
261	          model: StorageAutoScalerModel,
262	          resource: {
263	            metadata: {
264	              name: getName(storageAutoScaler),
265	              namespace: getNamespace(storageCluster),
266	            },
267	          },
268	        });
269	      }
270	
271	      setInProgress(false);
272	      closeModal();
273	    } catch (error) {
274	      setError(error);
275	      setInProgress(false);
276	    }
277	  };
278	
279	  React.useEffect(() => {
280	    if (alreadyEnabled) {
281	      setEnable(true);
282	      setCapacityLimit(storageAutoScaler.spec?.storageCapacityLimit);
283	      validate(true, storageAutoScaler.spec?.storageCapacityLimit);
284	    }
285	    // eslint-disable-next-line react-hooks/exhaustive-deps
286	  }, [alreadyEnabled, validate]);
287	  const Header = <ModalHeader>{t('Automatic capacity scaling')}</ModalHeader>;
288	  return (
289	    <Modal
290	      aria-label={t('Automatic capacity scaling')}
291	      className="odf-capacity-autoscaling__modal"
292	      header={Header}
293	      isOpen={isOpen}
294	      onClose={closeModal}
295	      showClose={false}
296	      hasNoBodyWrapper={true}
297	      variant={ModalVariant.large}
298	    >
299	      <ModalBody>
300	        {canEdit ? (
301	          <>
302	            <CapacityAutoScaling
303	              capacityLimit={capacityLimit}
304	              enable={enable}
305	              isEditView={true}
306	              onChange={onChange}
307	              onLimitSelect={onSelect}
308	              osdAmount={osdAmount}
309	              osdSize={osdSize}
310	            />
311	            {alreadyEnabled &&
312	              enable &&
313	              storageAutoScaler.status?.storageCapacityLimitReached && (
314	                <Alert
315	                  className="pf-v6-u-mt-md"
316	                  isInline
317	                  variant={AlertVariant.warning}
318	                  title={t('Cluster has reached its expansion limit.')}
319	                >
320	                  {t(
321	                    'Increasing the expansion limit is recommended to avoid capacity shortages and potential disruptions.'
322	                  )}
323	                </Alert>
324	              )}
325	            {alreadyEnabled && (
326	              <CapacityAutoscalingCurrentStatus
327	                currentStatus={phase}
328	                error={autoScalerError}
329	                lastExpansion={lastExpansion}
330	              />
331	            )}
332	            {alreadyEnabled && !enable && (
333	              <Alert
334	                className="pf-v6-u-mt-md"
335	                isInline
336	                variant={AlertVariant.warning}
337	                title={t('Disable automatic capacity scaling?')}
338	              >
339	                {t(
340	                  'Disabling Automatic capacity scaling will prevent the cluster from automatically increasing raw capacity when needed. This may lead to capacity shortages and potential disruptions.'
341	                )}
342	              </Alert>
343	            )}
344	            {validation && (
345	              <Alert
346	                className="pf-v6-u-mt-md"
347	                isInline
348	                variant={AlertVariant.danger}
349	                title={validation}
350	              ></Alert>
351	            )}
352	            {errorMessage && (
353	              <Alert
354	                className="pf-v6-u-mt-md"
355	                isInline
356	                variant={AlertVariant.danger}
357	                title={t('An error occurred')}
358	              >
359	                {errorMessage.message}
360	              </Alert>
361	            )}
362	          </>
363	        ) : !isLoaded || isLoadError ? (
364	          <StatusBox loaded={isLoaded} loadError={isLoadError} />
365	        ) : (
366	          <Alert
367	            className="pf-v6-u-mt-md"
368	            isInline
369	            variant={AlertVariant.danger}
370	            title={t(
371	              'Automatic capacity scaling is available only for dynamic storage.'
372	            )}
373	          >
374	            {t('Local storage is also present in the cluster.')}
375	          </Alert>
376	        )}
377	      </ModalBody>
378	      <ModalFooter>
379	        <Button
380	          key="cancel"
381	          variant={ButtonVariant.secondary}
382	          onClick={closeModal}
383	          data-test-id="modal-cancel-action"
384	        >
385	          {t('Cancel')}
386	        </Button>
387	        {canEdit &&
388	          (!inProgress ? (
389	            <Button
390	              key="save"
391	              data-test="modal-save-action"
392	              data-test-id="confirm-action"
393	              variant={ButtonVariant.primary}
394	              onClick={save}
395	              isDisabled={
396	                (alreadyEnabled &&
397	                  enable &&
398	                  capacityLimit ===
399	                    storageAutoScaler.spec?.storageCapacityLimit) ||
400	                (!alreadyEnabled && !enable) ||
401	                !!validation ||
402	                !!errorMessage
403	              }
404	            >
405	              {t('Save changes')}
406	            </Button>
407	          ) : (
408	            <LoadingInline />
409	          ))}
410	      </ModalFooter>
411	    </Modal>
412	  );
413	};
414	
415	export default CapacityAutoscalingModal;

